"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import {
    Navbar as HeroNavbar,
    NavbarBrand,
    NavbarContent,
    NavbarItem,
    NavbarMenuToggle,
    NavbarMenu,
    NavbarMenuItem,
    Button,
} from "@heroui/react";

export default function Navbar() {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isMenuOpen, setIsMenuOpen] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 40);
        };
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    const menuItems = [
        { name: "Sobre Mí", href: "/sobre-mi" },
        { name: "Servicios", href: "/servicios" },
        { name: "Enfoque", href: "/#enfoque" },
        { name: "Contacto", href: "/#contacto" },
    ];

    return (
        <HeroNavbar
            onMenuOpenChange={setIsMenuOpen}
            isMenuOpen={isMenuOpen}
            className={`fixed top-0 w-full transition-all duration-500 z-50 ${isScrolled
                ? "bg-white/95 backdrop-blur-3xl border-b border-navy/10 shadow-glass py-2"
                : "bg-transparent py-4"
                }`}
            maxWidth="xl"
            position="sticky"
        >
            <NavbarContent>
                <NavbarMenuToggle
                    aria-label={isMenuOpen ? "Cerrar menú" : "Abrir menú"}
                    className="sm:hidden text-navy"
                />
                <NavbarBrand as={Link} href="/" className="flex flex-col items-start gap-0">
                    <p className="font-serif text-2xl md:text-3xl text-navy font-bold leading-none">
                        Clínica de la Ansiedad
                    </p>
                    <p className="text-[10px] md:text-xs text-gold uppercase tracking-widest font-bold leading-none mt-1">
                        Catalunya · desde 1993
                    </p>
                </NavbarBrand>
            </NavbarContent>

            <NavbarContent className="hidden sm:flex gap-8" justify="center">
                {menuItems.map((item) => (
                    <NavbarItem key={item.name}>
                        <Link
                            href={item.href}
                            className="text-navy hover:text-gold transition-colors font-sans text-sm tracking-widest uppercase font-bold"
                        >
                            {item.name}
                        </Link>
                    </NavbarItem>
                ))}
            </NavbarContent>

            <NavbarContent justify="end">
                <NavbarItem>
                    <Button
                        as="a"
                        href="#contacto"
                        className="bg-gold text-white font-semibold rounded-full px-6 hover:bg-gold-light shadow-md transition-all"
                    >
                        Pedir cita
                    </Button>
                </NavbarItem>
            </NavbarContent>

            <NavbarMenu className="bg-cream/95 backdrop-blur-md pt-6">
                {menuItems.map((item, index) => (
                    <NavbarMenuItem key={`${item.name}-${index}`}>
                        <Link
                            className="w-full text-navy text-xl font-serif py-2 block border-b border-navy/10"
                            href={item.href}
                            onClick={() => setIsMenuOpen(false)}
                        >
                            {item.name}
                        </Link>
                    </NavbarMenuItem>
                ))}
                <NavbarMenuItem className="mt-6">
                    <Button
                        as="a"
                        href="#contacto"
                        className="w-full bg-gold text-white font-medium rounded-full py-6"
                        onClick={() => setIsMenuOpen(false)}
                    >
                        Pedir cita
                    </Button>
                </NavbarMenuItem>
            </NavbarMenu>
        </HeroNavbar>
    );
}
